export type Category = 'Body' | 'Antiage' | 'Oil' | 'Serum' | 'Personal Care' | 'Hand Creams' | 'Face' | 'Eyes' | 'Lips';

export interface Product {
  id: string;
  name: string;
  brand: string;
  price: number;
  category: Category;
  tags: string[];
  image: string;
  description: string;
  ingredients: string[];
  howToUse: string;
  rating: number;
  reviewsCount: number;
  sku: string;
  isNew?: boolean;
  isTopSeller?: boolean;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface AppState {
  cart: CartItem[];
  wishlist: string[]; // Product IDs
  searchQuery: string;
}

export type SortOption = 'default' | 'price-low' | 'price-high' | 'newest' | 'rating';

import { GoogleGenAI, Type } from "@google/genai";
import { Product } from "../types";
import { PRODUCTS } from "../constants";

export const aiSearch = async (query: string): Promise<Product[]> => {
  if (!query) return PRODUCTS;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Given the user search query: "${query}", rank the following products by relevance. 
      Return only the list of IDs in order of relevance as a JSON array.

      Products:
      ${PRODUCTS.map(p => `ID: ${p.id}, Name: ${p.name}, Description: ${p.description}, Tags: ${p.tags.join(', ')}`).join('\n')}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const resultIds: string[] = JSON.parse(response.text || "[]");
    return resultIds
      .map(id => PRODUCTS.find(p => p.id === id))
      .filter((p): p is Product => !!p);
  } catch (error) {
    console.error("Gemini search failed:", error);
    // Fallback to basic keyword search
    return PRODUCTS.filter(p => 
      p.name.toLowerCase().includes(query.toLowerCase()) || 
      p.description.toLowerCase().includes(query.toLowerCase())
    );
  }
};

import React, { createContext, useContext, useState, useCallback, ReactNode } from 'react';
import { CartItem, Product } from '../types';

interface AppContextType {
  cart: CartItem[];
  wishlist: string[];
  addToCart: (product: Product, quantity?: number) => void;
  removeFromCart: (productId: string) => void;
  updateQuantity: (productId: string, quantity: number) => void;
  toggleWishlist: (productId: string) => void;
  clearCart: () => void;
  cartTotal: number;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [wishlist, setWishlist] = useState<string[]>([]);

  const addToCart = useCallback((product: Product, quantity = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item
        );
      }
      return [...prev, { ...product, quantity }];
    });
  }, []);

  const removeFromCart = useCallback((productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  }, []);

  const updateQuantity = useCallback((productId: string, quantity: number) => {
    if (quantity < 1) return;
    setCart(prev => prev.map(item => 
      item.id === productId ? { ...item, quantity } : item
    ));
  }, []);

  const toggleWishlist = useCallback((productId: string) => {
    setWishlist(prev => 
      prev.includes(productId) 
        ? prev.filter(id => id !== productId) 
        : [...prev, productId]
    );
  }, []);

  const clearCart = useCallback(() => setCart([]), []);

  const cartTotal = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);

  return (
    <AppContext.Provider value={{
      cart,
      wishlist,
      addToCart,
      removeFromCart,
      updateQuantity,
      toggleWishlist,
      clearCart,
      cartTotal
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

