                Description
              </button>
              <button 
                onClick={() => setActiveTab('ingredients')}
                className={`pb-4 px-6 text-xs uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'ingredients' ? 'border-b-2 border-brand text-brand font-bold' : 'text-stone-400'}`}
              >
                Ingredients
              </button>
              <button 
                onClick={() => setActiveTab('howTo')}
                className={`pb-4 px-6 text-xs uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'howTo' ? 'border-b-2 border-brand text-brand font-bold' : 'text-stone-400'}`}
              >
                How to Use
              </button>
            </div>

            <div className="min-h-[150px] animate-fadeIn bg-stone-50/50 p-6 rounded-[5px] border border-stone-100">
              {activeTab === 'description' && (
                <div className="prose prose-stone prose-sm">
                  <p>{product.description}</p>
                  <p className="mt-4">Our commitment to clean beauty means this product is formulated without parabens, sulfates, or synthetic fragrances. Each bottle is carefully crafted to deliver visible results while maintaining skin health.</p>
