                <div className="text-stone-600 text-sm leading-relaxed">
                  <p className="font-bold mb-2 text-brand">Step-by-Step Instructions:</p>
                  <p>{product.howToUse}</p>
                  <p className="mt-4 italic text-xs">Tip: For best results, use consistently as part of your daily routine. Patch test before use.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Related Products */}
      {relatedProducts.length > 0 && (
        <section className="mt-32 pt-16 border-t border-stone-100">
          <h2 className="text-3xl font-serif text-stone-900 mb-12">You may also like</h2>
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-8">
            {relatedProducts.map(p => (
              <ProductCard key={p.id} product={p} />
            ))}
          </div>
        </section>
      )}
    </div>
  );
};

